processFunc:
(img, r, g, b, a, x, y, ...params) => {
  const [shift] = params;
  const w = img.width;
  const rIdx = 4 * (y * w + Math.min(x + shift, w - 1));  
  const bIdx = 4 * (y * w + Math.max(x - shift, 0));  
  const rr = img.pixels[rIdx];  
  const bb = img.pixels[bIdx + 2];
  return [rr, g, bb, a];
}
